def coalesce(layout, profile=None):
    if is_tuple(profile):
        assert len(layout) >= len(profile)
        return make_layout(
            chain(
                (coalesce(layout[i], profile[i]) for i in range(0, len(profile))),
                (layout[i] for i in range(len(profile), len(layout))),
            )
        )

    result_shape = [1]
    result_stride = [0]
    for shape, stride in zip(flatten(layout.shape), flatten(layout.stride)):
        if shape == 1:
            continue
        if result_shape[-1] == 1:
            result_shape[-1] = shape
            result_stride[-1] = stride
        elif result_shape[-1] * result_stride[-1] == stride:
            result_shape[-1] = result_shape[-1] * shape
        else:
            result_shape.append(shape)
            result_stride.append(stride)

    if len(result_shape) == 1:
        return Layout(result_shape[0], result_stride[0])
    return Layout(tuple(result_shape), tuple(result_stride))


def _zero_stride_like(shape):
    """Return a stride congruent to shape with all zero strides."""
    return prefix_product(shape, init=0)


def _ceil_div(a, b):
    """Ceiling division for non-negative a and positive b."""
    return (a + b - 1) // b


def _sign(x):
    if x > 0:
        return 1
    if x < 0:
        return -1
    return 0


def _compose_rank1(layoutA, layoutB):
    """Composition when layoutB is a rank-1 Layout and layoutA is coalesced."""
    # layoutA is rank-1: simple scaling
    if not is_tuple(layoutA.shape):
        return Layout(layoutB.shape, layoutB.stride * layoutA.stride)

    R = len(layoutA.shape)
    result_shape = []
    result_stride = []
    rest_shape = layoutB.shape
    rest_stride = layoutB.stride

    for i in range(R - 1):
        curr_shape = layoutA.shape[i]
        curr_stride = layoutA.stride[i]

        next_shape = _ceil_div(curr_shape, abs(rest_stride))
        next_stride = _ceil_div(abs(rest_stride), curr_shape) * _sign(rest_stride)

        if next_shape == 1 or rest_shape == 1:
            rest_stride = next_stride
        else:
            new_shape = min(next_shape, rest_shape)
            result_shape.append(new_shape)
            result_stride.append(rest_stride * curr_stride)
            rest_shape = rest_shape // new_shape
            rest_stride = next_stride

    if len(result_shape) == 0:
        return Layout(rest_shape, rest_stride * layoutA.stride[R - 1])

    if rest_shape == 1:
        if len(result_shape) == 1:
            return Layout(result_shape[0], result_stride[0])
        return Layout(tuple(result_shape), tuple(result_stride))

    result_shape.append(rest_shape)
    result_stride.append(rest_stride * layoutA.stride[R - 1])
    if len(result_shape) == 1:
        return Layout(result_shape[0], result_stride[0])
    return Layout(tuple(result_shape), tuple(result_stride))


def composition(layoutA, layoutB):
    """Return the layout equivalent to applying layoutB, then layoutA."""
    if layoutB is None:
        return layoutA

    if is_int(layoutB):
        layoutB = Layout(layoutB)

    if is_tuple(layoutB):
        # Pairwise composition with the modes of layoutA; None is a no-op.
        assert len(layoutB) <= len(layoutA)
        modes = []
        for i, b in enumerate(layoutB):
            if b is None:
                modes.append(layoutA[i])
            else:
                modes.append(composition(layoutA[i], b))
        for i in range(len(layoutB), len(layoutA)):
            modes.append(layoutA[i])
        return make_layout(*modes)

    # From here layoutB is a Layout.
    if is_tuple(layoutB.shape):
        # Recursively compose with each mode of layoutB.
        modes = [composition(layoutA, layoutB[i]) for i in range(len(layoutB.shape))]
        return make_layout(*modes)

    # Rank-1 layoutB.
    if layoutB.stride == 0:
        return Layout(layoutB.shape, _zero_stride_like(layoutB.shape))

    A = coalesce(layoutA)
    return _compose_rank1(A, layoutB)
